   private static int recipeCounter = 0;

   static IRecipe oreDictRecipe(ItemStack res, Object[] params) {
      ShapedOreRecipe rec = new ShapedOreRecipe((ResourceLocation)null, res, params);
      rec.setRegistryName(new ResourceLocation("thaumcraft", "shaped_ore_" + recipeCounter++));
      ForgeRegistries.RECIPES.register(rec);
      return rec;
   }

   static IRecipe shapelessOreDictRecipe(ItemStack res, Object[] params) {
      ShapelessOreRecipe rec = new ShapelessOreRecipe((ResourceLocation)null, res, params);
      rec.setRegistryName(new ResourceLocation("thaumcraft", "shapeless_ore_" + recipeCounter++));
      ForgeRegistries.RECIPES.register(rec);
      return rec;
   }

   static IRecipe shapelessNBTOreRecipe(ItemStack res, Object[] params) {
      ShapelessNBTOreRecipe rec = new ShapelessNBTOreRecipe(res, params);
      rec.setRegistryName(new ResourceLocation("thaumcraft", "shapeless_nbt_ore_" + recipeCounter++));
      ForgeRegistries.RECIPES.register(rec);
      return rec;
   }

